variable "cluster_name" {
  type        = string
  description = "Name for the AKS cluster"
}

# Story 8-1 — Env discriminator for custom RBAC role names.
# Used by rbac-roles.tf to produce env-scoped role names like
# `AKS Cluster Operator - cafehyna-dev` so a future `prod` env's roles cannot
# collide with `dev` in the Azure portal and operators can tell at a glance
# which environment a role grants access to.
variable "env_name" {
  type        = string
  description = "Story 8-1 (Epic 8 §FR29) — Environment discriminator (e.g., `cafehyna-dev`, `cafehyna-prd`) appended to custom AKS RBAC role names so a future `prod` env's roles cannot collide with `dev` and the operator sees the env at a glance in the Azure portal. Pass `var.environment` from the env layer."

  # P2 fix (2026-05-17 review): kebab-case-only validation. Azure role-definition
  # names accept a broad character set but the name is interpolated into
  # `"AKS Cluster Operator - ${var.env_name}"` and surfaces in the Azure portal,
  # `az role definition list` output, and `terraform output`. Tightening to
  # kebab-case (matching the project-wide `environment` convention —
  # `cafehyna-dev`, `cafehyna-prd`, `packer-dev`, etc.) rejects path separators,
  # whitespace, control chars, brackets, and uppercase — all of which would
  # either fail at ARM submission mid-apply or produce hostile operator UX.
  validation {
    condition     = can(regex("^[a-z0-9]+(-[a-z0-9]+)*$", var.env_name))
    error_message = "env_name must be lowercase kebab-case (e.g., `cafehyna-dev`, `cafehyna-prd`, `packer-dev`) — pattern: `^[a-z0-9]+(-[a-z0-9]+)*$`. Path separators, whitespace, brackets, uppercase, and control characters are rejected to prevent Azure-portal-hostile or apply-failing role names. Pass `var.environment` from the env layer."
  }
}

variable "resource_group_id" {
  type        = string
  description = "Resource ID of the Azure Resource Group (used as parent_id for AVM module and — Story 8-1 — as `scope` + `assignable_scopes` for the custom RBAC role definitions and assignments)."

  # P7 fix (2026-05-17 review, Story 8-1 §FR29): enforce resource-group-scoped
  # ID shape. The module passes this value to `azurerm_role_definition.scope`
  # AND `assignable_scopes`. Subscription-scoped (`/subscriptions/<guid>`) or
  # management-group-scoped (`/providers/Microsoft.Management/managementGroups/<name>`)
  # inputs are accepted by AzureRM as valid scopes and would silently widen the
  # role's assignable surface beyond the AKS RG, breaching the Story 8-1
  # least-privilege contract. Reject upstream.
  validation {
    condition     = can(regex("^/subscriptions/[0-9a-fA-F-]{36}/resourceGroups/[^/]+$", var.resource_group_id))
    error_message = "resource_group_id must be a resource-group-scoped ID of the form `/subscriptions/<guid>/resourceGroups/<name>`. Subscription-scoped and management-group-scoped values are forbidden by Story 8-1 (§FR29) least-privilege contract — the custom RBAC roles must not be assignable beyond the AKS resource group."
  }
}

