# Node pools
variable "default_node_pool" {
  type = object({
    name       = string
    vm_size    = string
    node_count = number
    max_pods   = optional(number, 110)
    zones      = optional(list(string), ["1"])
    upgrade_settings = optional(object({
      max_surge = optional(string, "10%")
    }), { max_surge = "10%" })
  })
  description = "Configuration for the system (default) node pool"

  # Story 7-2 (FR26) — Module-layer absolute floor on the system pool count.
  # The module is environment-agnostic and CANNOT see env-layer toggles like
  # `allow_reduced_node_count`, so the depth check here is the absolute minimum
  # (2 — what `allow_reduced_node_count = true` permits at the env layer). The
  # env layer enforces the conditional 3-vs-2 logic; this is depth only.
  # Iter-2 patch P1: integer-only via `floor(x) == x` mirrors the env-layer
  # check and the `image_cleaner_interval_hours` pattern from Story 5-2.
  validation {
    condition     = floor(var.default_node_pool.node_count) == var.default_node_pool.node_count && var.default_node_pool.node_count >= 2
    error_message = "default_node_pool.node_count must be a whole number >= 2 (AKS Baseline absolute floor — docs/aks-baseline-cluster-reference.md:201). The env layer enforces the conditional `>= 3 unless allow_reduced_node_count = true` rule per Story 7-2 FR26."
  }

  # Node pool name shape — Azure Linux pool constraints. The default system
  # pool is canonically named `system` (AKS API-default; cannot be renamed
  # post-create without rebuilding the cluster). Disambiguation across envs
  # comes from the Kubernetes label `environment` (Story 5-3 — see
  # system_node_labels in the env layer) and from per-cluster MC_* RG
  # isolation, NOT from the pool name itself. See terraform/CLAUDE.md
  # § Key Patterns — "Node pool names" for the full convention rationale.
  validation {
    condition     = can(regex("^[a-z][a-z0-9]{0,11}$", var.default_node_pool.name))
    error_message = "default_node_pool.name must match Linux AKS pool name constraints: 1-12 chars, lowercase alphanumeric, starting with a letter (`^[a-z][a-z0-9]{0,11}$`). Convention: use `system` — the AKS API-canonical name. The Kubernetes label `environment` (Story 5-3) discriminates across envs; per-cluster MC_* RG isolation prevents Azure-side collision. See terraform/CLAUDE.md § Key Patterns."
  }
}

variable "user_node_pools" {
  type = map(object({
    name                 = string
    vm_size              = string
    min_count            = number
    max_count            = number
    max_pods             = optional(number, 110)
    os_disk_size_gb      = optional(number, 128)
    zones                = optional(list(string), ["1"])
    auto_scaling_enabled = optional(bool, true)
    node_labels          = optional(map(string), null)
    os_disk_type         = optional(string, null)
    upgrade_settings = optional(object({
      max_surge = optional(string, "10%")
    }), { max_surge = "10%" })
  }))
  description = "Map of user node pool configurations. Story 5-3 (FR21) adds optional `node_labels` for pool-identity scheduling/policy, and Story 5-3 (FR20) adds optional `os_disk_type` (Managed|Ephemeral) for the AKS Baseline ephemeral-OS path. Both default to null so existing callers that don't set them produce no diff."
  default     = {}

  # Story 7-2 (FR26) — Module-layer absolute floor on every user node pool's min_count.
  # Non-overridable per the AKS Baseline (docs/aks-baseline-cluster-reference.md:214):
  # single-node user pools have no in-zone failover during a node patch/maintenance window.
  # No env-layer toggle relaxes this floor; the user pool is always >= 2.
  # Iter-2 patch P1: integer-only via `floor(x) == x` mirrors the env-layer check.
  validation {
    condition     = alltrue([for pool in values(var.user_node_pools) : floor(pool.min_count) == pool.min_count && pool.min_count >= 2])
    error_message = "Every user_node_pools[*].min_count must be a whole number >= 2 per AKS Baseline (docs/aks-baseline-cluster-reference.md:214). This floor is non-overridable — workload pools always need >= 2 for in-zone failover during a single-node patch/maintenance window."
  }

  # Node pool name shape — Azure Linux pool constraints (1-12 chars, lowercase
  # alphanumeric, must start with a letter). Convention: generic descriptive
  # names (e.g., `workload`, `monitoring`) rather than env-prefixed names —
  # 12-char limit makes prefix patterns impractical (`cafehyna-dev` alone is 12
  # chars). Disambiguation across envs comes from the Kubernetes label
  # `environment` injected via node_labels (Story 5-3), and from per-cluster
  # MC_* RG isolation on the Azure side. See terraform/CLAUDE.md § Key
  # Patterns — "Node pool names" for the full convention rationale.
  validation {
    condition     = alltrue([for pool in values(var.user_node_pools) : can(regex("^[a-z][a-z0-9]{0,11}$", pool.name))])
    error_message = "Every user_node_pools[*].name must match Linux AKS pool name constraints: 1-12 chars, lowercase alphanumeric, starting with a letter (`^[a-z][a-z0-9]{0,11}$`). Convention: use generic descriptive names (`workload`, `monitoring`, etc.). The Kubernetes label `environment` (Story 5-3) discriminates across envs; per-cluster MC_* RG isolation prevents Azure-side collision. See terraform/CLAUDE.md § Key Patterns."
  }
}

