variable "sku_name" {
  type        = string
  description = "AKS SKU name — cluster type. 'Base' for standard managed clusters; 'Automatic' for AKS Automatic (managed defaults, opinionated). Required by AKS API 2025-10-01."
  default     = "Base"

  validation {
    condition     = contains(["Base", "Automatic"], var.sku_name)
    error_message = "sku_name must be Base or Automatic."
  }
}

variable "cluster_identity_id" {
  type        = string
  description = <<-EOT
    Resource ID of the User-Assigned Managed Identity to attach as the AKS
    cluster identity. REQUIRED when `private_cluster_enabled = true` AND a
    customer-managed `private_dns_zone_id` is supplied — Azure rejects
    SystemAssigned identities in that combination
    (`400 OnlySupportedOnUserAssignedMSICluster`). The caller pre-creates
    the UAMI and pre-grants `Private DNS Zone Contributor` on the zone
    BEFORE this module's apply (Azure pre-validates the role assignment).
  EOT
}

variable "cluster_identity_principal_id" {
  type        = string
  description = <<-EOT
    Principal ID (object ID) of the User-Assigned Managed Identity passed via
    `cluster_identity_id`. Used by the module's Network Contributor role
    assignments on the node pool subnets (identity.tf). REQUIRED in addition
    to `cluster_identity_id` because the AVM module's `identity_principal_id`
    output returns null for UAMI clusters — Azure only populates the top-level
    `identity.principalId` field for SystemAssigned identities. For UAMI, the
    principal lives at `identity.userAssignedIdentities[<id>].principalId` and
    the AVM module doesn't expose a derived output for it. Caller has the
    value at `azurerm_user_assigned_identity.<name>.principal_id`.
  EOT
}

