# AKS Cluster Module
# Uses Azure Verified Module for AKS managed clusters

data "azurerm_client_config" "current" {}

module "aks" {
  source  = "Azure/avm-res-containerservice-managedcluster/azurerm"
  version = "0.5.3"

  name             = var.cluster_name
  location         = var.location
  parent_id        = var.resource_group_id
  enable_telemetry = var.enable_avm_telemetry
  tags             = var.common_tags

  # Kubernetes version and upgrades
  kubernetes_version = var.kubernetes_version

  # AKS API 2025-10-01 (used by upstream AVM module v0.5.3) requires BOTH
  # sku.name and sku.tier. `name` is the cluster type ("Base" standard
  # workload or "Automatic" for AKS Automatic). `tier` is the support tier
  # (Free | Standard | Premium). Omitting `name` returns
  # 400 InvalidRequestContent "Required property 'name' not found in 'sku'".
  sku = {
    name = var.sku_name
    tier = var.sku_tier
  }

  auto_upgrade_profile = {
    upgrade_channel = var.automatic_upgrade_channel
  }

  # DNS and private cluster
  dns_prefix = var.dns_prefix

  api_server_access_profile = var.private_cluster_enabled ? {
    enable_private_cluster = true
    private_dns_zone       = var.private_dns_zone_id
  } : null

  # Identity — User-Assigned MI (required when private cluster + custom DNS zone).
  # Caller pre-creates the UAMI and pre-grants `Private DNS Zone Contributor`
  # on `var.private_dns_zone_id` so Azure's pre-create validation passes.
  # SystemAssigned would return `400 OnlySupportedOnUserAssignedMSICluster`
  # in this configuration.
  managed_identities = {
    system_assigned            = false
    user_assigned_resource_ids = [var.cluster_identity_id]
  }

  # OIDC + Workload Identity
  oidc_issuer_profile = var.enable_workload_identity ? {
    enabled = true
  } : null

  security_profile = {
    workload_identity = var.enable_workload_identity ? {
      enabled = true
    } : null
    defender = var.enable_defender ? {
      log_analytics_workspace_resource_id = var.defender_log_analytics_workspace_id
      security_monitoring = {
        enabled = true
      }
    } : null
    # AVM v0.5.3 exposes image cleaner under `security_profile.image_cleaner`,
    # not as top-level module arguments. Bump to ≥0.6.x to switch to the
    # top-level form once the AVM module exposes it.
    image_cleaner = var.enable_image_cleaner ? {
      enabled        = true
      interval_hours = var.image_cleaner_interval_hours
    } : null
  }

  # Azure Policy add-on (OPA Gatekeeper)
  addon_profile_azure_policy = var.enable_azure_policy ? {
    enabled = true
  } : null

  # Azure RBAC
  aad_profile = {
    enable_azure_rbac = true
    managed           = true
    tenant_id         = data.azurerm_client_config.current.tenant_id
  }
  disable_local_accounts = true

  # Network profile
  network_profile = {
    network_plugin      = var.network_profile.network_plugin
    network_plugin_mode = var.network_profile.network_plugin_mode
    network_dataplane   = var.network_profile.network_data_plane
    network_policy      = var.network_profile.network_policy
    pod_cidr            = var.network_profile.pod_cidr
    service_cidr        = var.network_profile.service_cidr
    dns_service_ip      = var.network_profile.dns_service_ip
    outbound_type       = var.network_profile.outbound_type
  }

  # ─── Node Pool Naming Convention (terraform/CLAUDE.md § Key Patterns) ────
  # Pool names are intentionally generic — `system` for the default pool
  # (AKS API-canonical, unrenameable post-create) and short descriptive labels
  # like `workload` for user pools. Two layers of disambiguation:
  #   1. Kubernetes — each pool carries `environment = var.environment` in
  #      its node_labels (Story 5-3 — see system_node_labels and
  #      user_node_pools[*].node_labels in the env layer).
  #   2. Azure — each cluster gets its own `MC_*` managed RG; underlying
  #      VMSS named `aks-{poolname}-{clusterhash}-vmss` cannot collide
  #      across clusters because they live in different MC_* RGs.
  # Linux pool name limit is 12 chars, so env-discriminator prefixes don't
  # fit (`cafehyna-dev` alone is 12 chars). Validation lives in
  # variables.tf (default_node_pool + user_node_pools).
  # ─────────────────────────────────────────────────────────────────────────

  # System (default) node pool — uses system node subnet
  # Story 5-3 (FR19, FR21): node_labels for pool identity; node_taints isolates system services
  # from arbitrary workloads (CriticalAddonsOnly=true:NoSchedule per AKS Baseline). Both arguments
  # are top-level optional on `default_agent_pool` per AVM v0.5.3 schema (variables.tf lines 457, 459).
  default_agent_pool = {
    name               = var.default_node_pool.name
    vm_size            = var.default_node_pool.vm_size
    count_of           = var.default_node_pool.node_count
    max_pods           = var.default_node_pool.max_pods
    vnet_subnet_id     = var.system_node_subnet_id
    availability_zones = var.default_node_pool.zones
    node_labels        = var.system_node_labels
    node_taints        = var.system_node_taints

    upgrade_settings = {
      max_surge = var.default_node_pool.upgrade_settings.max_surge
    }
  }

  # Node Auto-Provisioning (NAP/Karpenter) — mutually exclusive with cluster autoscaler
  node_provisioning_profile = var.enable_nap ? {
    mode               = "Auto"
    default_node_pools = var.nap_default_node_pools
  } : null

  # User node pools — each gets its own subnet (disabled when NAP is active)
  # Story 5-3 (FR20, FR21): per-pool node_labels for pool-identity and policy targeting;
  # per-pool os_disk_type makes the Managed/Ephemeral choice explicit at the pool literal.
  # Both fields are top-level optional on `agent_pools.<key>` per AVM v0.5.3 schema.
  agent_pools = var.enable_nap ? {} : {
    for k, v in var.user_node_pools : k => {
      name                = v.name
      vm_size             = v.vm_size
      min_count           = v.min_count
      max_count           = v.max_count
      max_pods            = v.max_pods
      os_disk_size_gb     = v.os_disk_size_gb
      vnet_subnet_id      = var.workload_node_subnet_id
      availability_zones  = v.zones
      enable_auto_scaling = v.auto_scaling_enabled
      mode                = "User"
      os_type             = "Linux"
      node_labels         = v.node_labels
      os_disk_type        = v.os_disk_type

      upgrade_settings = {
        max_surge = v.upgrade_settings.max_surge
      }
    }
  }

  # Key Vault Secrets Provider (CSI driver)
  addon_profile_key_vault_secrets_provider = var.enable_key_vault_secrets_provider ? {
    enabled = true
    config = {
      enable_secret_rotation = true
    }
  } : null

  # Container Insights (OMS agent)
  addon_profile_oms_agent = var.enable_oms_agent ? {
    enabled = true
    config = {
      log_analytics_workspace_resource_id = var.log_analytics_workspace_id
    }
  } : null

  # Managed Prometheus
  prometheus_workspace_id = var.enable_prometheus ? var.monitor_workspace_id : null

  # Storage profile
  storage_profile = {
    blob_csi_driver = {
      enabled = var.enable_blob_csi_driver
    }
    disk_csi_driver = {
      enabled = true
    }
    file_csi_driver = {
      enabled = true
    }
    snapshot_controller = {
      enabled = true
    }
  }

  # Story 7-1 (AKS Baseline FR25) — Control plane diagnostic settings.
  # Wires the 4 essential log categories (ClusterAutoscaler, KubeControllerManager,
  # guard, kube-audit-admin) to the Log Analytics workspace owned by the shared_services
  # module. `metric_categories = []` keeps this story to logs only — metrics already
  # flow via the OMS agent (Container Insights) per the AKS Baseline guidance.
  #
  # DO NOT REMOVE `log_groups = []`. AVM v0.5.3 emits TWO independent
  # `dynamic "enabled_log"` blocks — one driven by `log_categories`, one by
  # `log_groups` — and AzureRM accepts both forms simultaneously (it does NOT
  # mutually exclude them at the provider layer). The AVM `log_groups` default is
  # `["allLogs"]`, which would silently enable EVERY supported category through the
  # second loop — including the cost-spike `kube-audit` and `KubeScheduler` that
  # `control_plane_log_categories` validation explicitly rejects. Setting
  # `log_groups = []` here is the only thing keeping that side-door closed; removing
  # it would silently defeat AC #2.
  diagnostic_settings = var.enable_control_plane_diagnostics ? {
    control-plane = {
      name                           = "diag-${var.cluster_name}-control-plane"
      workspace_resource_id          = var.log_analytics_workspace_id
      log_categories                 = toset(var.control_plane_log_categories)
      log_groups                     = []
      metric_categories              = []
      log_analytics_destination_type = "Dedicated"
    }
  } : {}
}

